// =============================================================================
// D / V — Конфигурация прототипа
// =============================================================================
// ВСЕ числа здесь — placeholder'ы. Документ (раздел 11, 12) прямо говорит: каузальная
// структура задана, а "насколько" решается ТОЛЬКО прототипом. Поэтому каждая величина,
// которая влияет на сходимость каната, вынесена сюда и снабжена ссылкой на раздел GDD.
//
// Цель первого среза (GDD §12): дать петле "канат + экономика" побежать и увидеть —
// шкала тьмы колеблется вокруг центра или сваливается в один край.
// =============================================================================

export const CONFIG = {
  // --- Мир / симуляция -------------------------------------------------------
  world: {
    width: 1200,
    height: 800,
    dt: 1 / 60,              // фиксированный шаг симуляции (детерминизм)
    sessionMaxSeconds: 240,  // потолок длины сессии для headless-прогона
    maxEnemies: 80,          // предохранитель от взрыва числа врагов
  },

  // --- Спавн врагов из центра (GDD §3, §7) ----------------------------------
  // Две независимые оси: СОСТАВ (растёт со временем сессии) и ИНТЕНСИВНОСТЬ (тьма).
  // В срезе один тип врага, поэтому "состав" = частота спавна растёт со временем,
  // а "интенсивность" (тьма) подкручивает урон/скорость атаки, НЕ hp (§3).
  spawn: {
    baseInterval: 0.9,       // сек между спавнами в начале сессии (давит на D ощутимо)
    intervalSessionGain: 0.6,// насколько частота растёт к концу сессии (состав)
    burst: 1,                // сколько врагов за один спавн
    centerJitter: 40,        // радиус разброса точки спавна вокруг центра
  },

  // --- Враг (один тип: ближнебойный) (GDD §3) -------------------------------
  enemy: {
    hp: 40,
    radius: 12,
    speed: 70,               // px/сек
    contactDamage: 8,        // базовый урон в светлом мире
    attackInterval: 0.8,     // сек между ударами
    attackRange: 22,         // дистанция, с которой бьёт
    // Тьма добавляет ТРЕБОВАТЕЛЬНОСТЬ, а не HP (§3):
    damageDarkGain: 1.5,     // урон *= (1 + darkness * gain)
    attackSpeedDarkGain: 0.8,// интервал атаки /= (1 + darkness * gain)
    // КРИТИЧНО для каната: в светлом мире враг (70) медленнее D (110) → D кайтит соло.
    // В тьме враг ускоряется и ДОГОНЯЕТ D → D больше не выживает в одиночку (§1) →
    // нуждается в V → V зарабатывает на хиле → тянет мир к свету. Это и замыкает
    // отрицательную обратную связь каната ("тьма сжимает V-кромку", §3).
    speedDarkGain: 1.0,      // скорость *= (1 + darkness * gain): при darkness=1 → 140 > 110
  },

  // --- D: сторона без кнопки спасения (GDD §1, §2) --------------------------
  // Высокий урон, нулевая автономность выживания. Нет рывка/щита/самохила.
  D: {
    hp: 100,
    radius: 14,
    speed: 110,
    shotDamage: 22,
    shotInterval: 0.5,
    shotRange: 320,
    projectileSpeed: 520,
    projectileRadius: 5,
  },

  // --- V: сторона с глаголами спасения (GDD §1, §2) ------------------------
  // Выстрел = хил союзника / урон врагу одним снарядом. Самодостаточен в выживании,
  // НЕ самодостаточен в добивании. В срезе — одноцель (старт ветки §2).
  V: {
    hp: 90,
    radius: 13,
    speed: 115,
    healPower: 16,           // хил союзнику ИЛИ урон врагу (один снаряд, §2)
    burnFactor: 0.7,         // урон врагу = healPower * burnFactor (V слабее в добивании)
    shotInterval: 0.45,
    shotRange: 380,          // длиннее луча D (одноцель-ветка работает дальше, §2)
    projectileSpeed: 560,
    projectileRadius: 5,
  },

  // --- Экономика (GDD §5) ---------------------------------------------------
  // Валюта — стержень. V получает за ЭФФЕКТИВНЫЙ хил D (оверхил = 0).
  economy: {
    killBase: 6,             // валюта за убийство врага (идёт добившему)
    healPayPerHP: 0.5,       // валюта V за каждый реально отыгранный HP на D
    darkCurrencyGain: 1.4,   // бонус тёмного мира всем: *= (1 + darkness * gain) (§5)
  },

  // --- Ноды прокачки = движок баланса (GDD §4) ------------------------------
  // Каждая купленная нода — это и личная сила, и голос за состояние мира (вложенное очко).
  nodes: {
    cost: 14,                // валюта за одну ноду
    dDamageStep: 6,          // +урон D за ноду
    dDarkPoints: 1,          // +очков в тёмную чашу каната
    vHealStep: 3,            // +сила хила/прокачки V за ноду
    vLightPoints: 1,         // +очков в светлую чашу каната
  },

  // --- Шкала тьмы / канат (GDD §4) ------------------------------------------
  // darkness ∈ [0,1]. 0 = светло (старт, ничего не вложено — §4 "светел по построению").
  // Питается ЧИСТЫМ вложением (dark - light). Гистерезис в центре (мёртвая зона §4),
  // чтобы ранний мир не дрожал от первых очков.
  darkness: {
    normalizer: 24,          // сколько чистых очков = полная тьма (1.0)
    deadzonePoints: 3,       // мёртвая зона у нуля (гистерезис §4)
    smoothing: 1.5,          // скорость подтягивания darkness к цели (в долях/сек)
  },

  // --- Крахи (GDD §6) -------------------------------------------------------
  // "Все V мертвы" = яростная вспышка: урон D взлетает, но D тают и гибнут.
  // "Все D мертвы" = тихое угасание (обрабатывается как терминальный статус).
  crash: {
    furyDamageMul: 6,        // во сколько взлетает урон D, когда все V мертвы
    furyDecayPerSec: 28,     // сколько hp/сек теряет D во время ярости
  },

  // --- Поведение ботов (GDD §2 V-кромка, §1 роли) ---------------------------
  // Боты ведут обе стороны, чтобы канат бежал автономно и его можно было наблюдать.
  ai: {
    dEngageRange: 150,       // D подходит на эту дистанцию к врагу и стреляет
    dRetreatHp: 0.25,        // доля hp, ниже которой D жмётся к V
    vKromkaDistance: 90,     // целевая дистанция V до D (близко для хила)
    vDangerDistance: 70,     // ближе этого враг — V отступает (V-кромка §2)
    investEagerness: 1.0,    // 1 = покупает ноду как только хватает валюты (жадно)
    // Отзывчивая политика D (тест §10/§4): D воздерживается от вложения в тьму,
    // когда мир уже темнее этого порога — "не класть своих V под ещё большее давление".
    // 1.0 и выше = жадный D без тормозов (дампит очки всегда). <1.0 = своекорыстный,
    // но осмотрительный D с целевым уровнем тьмы.
    dDarkStopAt: 2.0,
  },
};

// Утилита: глубокое слияние оверрайдов (для свипов параметров из headless-раннера).
export function withOverrides(base, overrides) {
  if (!overrides) return base;
  const out = Array.isArray(base) ? [...base] : { ...base };
  for (const key of Object.keys(overrides)) {
    const v = overrides[key];
    if (v && typeof v === 'object' && !Array.isArray(v) && typeof out[key] === 'object') {
      out[key] = withOverrides(out[key], v);
    } else {
      out[key] = v;
    }
  }
  return out;
}
